try {
  const rawOutput = $input.item.json.stdout;
  const leads = JSON.parse(rawOutput);
  return leads.map(l => ({ json: l }));
} catch (err) {
  return [{ json: { error: err.message } }];
}

try {
  // The API returns text. We need to extract the JSON block from it.
  const gptText = $input.item.json.response || $input.item.json.text || '';
  const jsonMatch = gptText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    let jsonStr = jsonMatch[0];
    // Sanitize unescaped control characters (like raw newlines) in the LLM response JSON
    jsonStr = jsonStr.replace(/[\u0000-\u001F]+/g, (match) => {
      if (match.includes('\n')) return '\\n';
      if (match.includes('\r')) return '\\r';
      if (match.includes('\t')) return '\\t';
      return '';
    });
    const parsed = JSON.parse(jsonStr);
    return {
      json: {
        name: $node["Parse Scraper JSON Output"].json.name,
        website: $node["Parse Scraper JSON Output"].json.website,
        phone: $node["Parse Scraper JSON Output"].json.phone,
        hasMobileApp: parsed.hasMobileApp,
        emails: parsed.emails && parsed.emails.length > 0 ? parsed.emails : $node["Parse Scraper JSON Output"].json.emails,
        pitchHtml: parsed.pitchHtml
      }
    };
  }
  return { json: { error: 'No JSON found in response', raw: gptText } };
} catch (err) {
  return { json: { error: err.message } };
}
